parameters.jsonSchemaExample:
{
  "roadmap_steps": [
    {
      "step_number": 1,
      "title": "Semaine 1 : Repositionner votre profil LinkedIn",
      "actionable_advice": "Réécrivez votre titre LinkedIn pour cibler vos clients idéaux avec des mots-clés axés sur les résultats. Exemple : 'Développeur Next.js — J'aide les startups à lancer leur MVP en 4 semaines'.",
      "daily_plan": [
        { "day": "Lundi",    "tasks": ["Analyser 5 profils LinkedIn de freelances leaders dans votre niche", "Lister 10 mots-clés clients utilisés dans leurs offres"] },
        { "day": "Mardi",    "tasks": ["Réécrire votre titre LinkedIn avec la formule : Rôle + Cible + Résultat", "Mettre à jour le résumé (About) en 3 paragraphes : problème client / votre solution / preuve sociale"] },
        { "day": "Mercredi", "tasks": ["Optimiser la section Expérience avec des résultats chiffrés pour chaque mission", "Ajouter 3 études de cas courtes dans la section Projets"] },
        { "day": "Jeudi",    "tasks": ["Demander 2 recommandations à d'anciens clients ou collaborateurs", "Rejoindre 5 groupes LinkedIn actifs dans votre secteur"] },
        { "day": "Vendredi", "tasks": ["Publier votre premier post LinkedIn de repositionnement (avant/après)", "Identifier 20 prospects qualifiés à contacter la semaine prochaine"] }
      ]
    },
    {
      "step_number": 2,
      "title": "Semaine 2 : Activer la prospection directe",
      "actionable_advice": "Envoyez 10 messages personnalisés par jour sur LinkedIn à des leads qualifiés en utilisant le template : 'Bonjour [prénom], j'ai vu que vous cherchez [besoin]. J'ai aidé [client similaire] à [résultat concret]. Seriez-vous disponible pour un appel de 15 min ?'.",
      "daily_plan": [
        { "day": "Lundi",    "tasks": ["Rédiger 3 variantes du message de prospection (ton direct, ton valeur, ton social proof)", "Contacter les 10 premiers prospects de votre liste"] },
        { "day": "Mardi",    "tasks": ["Suivre les réponses et relancer les non-répondeurs avec une valeur ajoutée", "Contacter 10 nouveaux prospects"] },
        { "day": "Mercredi", "tasks": ["Analyser les taux de réponse et identifier le message le plus performant", "Contacter 10 nouveaux prospects avec le meilleur template"] },
        { "day": "Jeudi",    "tasks": ["Planifier les appels de découverte avec les prospects intéressés", "Préparer votre script d'appel de 15 minutes"] },
        { "day": "Vendredi", "tasks": ["Faire le bilan de la semaine : nombre de contacts, taux de réponse, appels planifiés", "Préparer la liste des 50 prospects de la semaine prochaine"] }
      ]
    }
  ],
  "marketing_strategy": {
    "organic": "Publiez 3x/semaine sur LinkedIn : 1 post de valeur (conseil technique), 1 étude de cas client, 1 post de personal branding. Utilisez les hashtags de votre niche. Interagissez avec 20 posts de votre cible par jour pendant 15 minutes.",
    "paid": "Lancez une campagne LinkedIn Ads avec un budget de 10€/jour ciblant les décideurs (CEO/CTO) de startups SaaS en France. Créez 2 variantes d'annonces A/B testant l'approche 'gain' vs 'douleur'.",
    "shorts_scripts": [
      {
        "topic": "Comment trouver votre premier client freelance en 7 jours",
        "structure": "Hook fort → Problème commun → Solution en 3 étapes → CTA",
        "hook": "Tu es freelance depuis 3 mois et tu n'as toujours pas de client ? Voici la méthode exacte que j'ai utilisée.",
        "body": "Étape 1 : Identifie ta niche ultra-précise. Pas 'développeur web', mais 'je crée des landing pages qui convertissent pour les coachs'. Étape 2 : Va sur LinkedIn et contacte 10 personnes dans ta cible chaque jour avec un message personnalisé de 3 lignes max. Étape 3 : Offre un audit gratuit de 20 minutes pour montrer ta valeur avant de vendre.",
        "cta": "Abonne-toi pour voir comment j'ai décroché mes 5 premiers clients en moins d'un mois."
      }
    ]
  }
}
